--
-- Table structure for table `deliveries`
--

DROP TABLE IF EXISTS `deliveries`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `deliveries` (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `area_id` bigint NOT NULL,
  `merchant_id` bigint NOT NULL,
  `courier_id` bigint DEFAULT NULL,
  `recipient_id` bigint DEFAULT NULL,
  `state` varchar(24) COLLATE utf8mb4_unicode_ci NOT NULL,
  `dispatch_mode` varchar(16) COLLATE utf8mb4_unicode_ci NOT NULL,
  `payment_method` varchar(16) COLLATE utf8mb4_unicode_ci NOT NULL,
  `proof_method` varchar(16) COLLATE utf8mb4_unicode_ci NOT NULL,
  `pickup_address` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `pickup_neighborhood` varchar(120) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `pickup_lat` float DEFAULT NULL,
  `pickup_lng` float DEFAULT NULL,
  `dropoff_address` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `dropoff_number` varchar(20) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `dropoff_complement` varchar(120) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `dropoff_neighborhood_id` bigint NOT NULL,
  `dropoff_lat` float DEFAULT NULL,
  `dropoff_lng` float DEFAULT NULL,
  `distance_m` int DEFAULT NULL,
  `fee_cents` int NOT NULL,
  `items_description` varchar(500) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `items_quantity` int NOT NULL,
  `declared_value_cents` int DEFAULT NULL,
  `weight_g` int DEFAULT NULL,
  `length_cm` int DEFAULT NULL,
  `width_cm` int DEFAULT NULL,
  `height_cm` int DEFAULT NULL,
  `reference_number` varchar(64) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `notes` varchar(500) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `public_token` varchar(32) COLLATE utf8mb4_unicode_ci NOT NULL,
  `origin` varchar(16) COLLATE utf8mb4_unicode_ci NOT NULL,
  `accepted_at` datetime(6) DEFAULT NULL,
  `collected_at` datetime(6) DEFAULT NULL,
  `delivered_at` datetime(6) DEFAULT NULL,
  `finalized_at` datetime(6) DEFAULT NULL,
  `cancelled_at` datetime(6) DEFAULT NULL,
  `cancel_reason` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `cancel_actor_user_id` bigint DEFAULT NULL,
  `anonymized_at` datetime(6) DEFAULT NULL,
  `created_at` datetime(6) NOT NULL,
  `updated_at` datetime(6) NOT NULL,
  `cancel_cost_cents` int NOT NULL DEFAULT '0',
  `courier_collection_method` varchar(16) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `receipt_method` varchar(16) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `team_ids` json DEFAULT NULL,
  `price_cents` int DEFAULT NULL,
  `image_key` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `scheduled_at` datetime DEFAULT NULL,
  `inngest_event_id` varchar(128) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `zona_id` bigint DEFAULT NULL,
  `dropoff_reference` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `pix_transaction_id` varchar(64) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `pix_qr_code` text COLLATE utf8mb4_unicode_ci,
  `pix_qr_code_base64` text COLLATE utf8mb4_unicode_ci,
  PRIMARY KEY (`id`),
  UNIQUE KEY `uq_deliveries_public_token` (`public_token`),
  KEY `ix_deliveries_area_id` (`area_id`),
  KEY `ix_deliveries_merchant_id` (`merchant_id`),
  KEY `ix_deliveries_courier_id` (`courier_id`),
  KEY `ix_deliveries_recipient_id` (`recipient_id`),
  KEY `ix_deliveries_dropoff_neighborhood_id` (`dropoff_neighborhood_id`),
  KEY `ix_deliveries_area_id_merchant_id_created_at` (`area_id`,`merchant_id`,`created_at`),
  KEY `ix_deliveries_area_id_state` (`area_id`,`state`),
  KEY `ix_deliveries_zona_id` (`zona_id`),
  CONSTRAINT `fk_deliveries_area_id_areas` FOREIGN KEY (`area_id`) REFERENCES `areas` (`id`) ON DELETE RESTRICT ON UPDATE RESTRICT,
  CONSTRAINT `fk_deliveries_courier_id_couriers` FOREIGN KEY (`courier_id`) REFERENCES `couriers` (`id`) ON DELETE RESTRICT ON UPDATE RESTRICT,
  CONSTRAINT `fk_deliveries_dropoff_neighborhood_id_neighborhoods_catalog` FOREIGN KEY (`dropoff_neighborhood_id`) REFERENCES `neighborhoods_catalog` (`id`) ON DELETE RESTRICT ON UPDATE RESTRICT,
  CONSTRAINT `fk_deliveries_merchant_id_merchants` FOREIGN KEY (`merchant_id`) REFERENCES `merchants` (`id`) ON DELETE RESTRICT ON UPDATE RESTRICT,
  CONSTRAINT `fk_deliveries_recipient_id_recipients` FOREIGN KEY (`recipient_id`) REFERENCES `recipients` (`id`) ON DELETE RESTRICT ON UPDATE RESTRICT,
  CONSTRAINT `fk_deliveries_zona_id_zonas` FOREIGN KEY (`zona_id`) REFERENCES `zonas` (`id`) ON DELETE SET NULL ON UPDATE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=106 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

